    table.clear(TPGMeWwN_flat)
    TPGMeWwN_flat = nil
    
    if CGJDkycg then 
        local result = CGJDkycg(...)
        decrypted = nil
        CGJDkycg = nil
        if type(result) == "function" then
            return result(...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(ZCFQTUzM)) 
    end
end
